import{_ as t,o as a,c as s,a3 as o}from"./chunks/framework.DACwFHq9.js";const p=JSON.parse('{"title":"Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":1784054081000}'),r={name:"release-notes.md"};function n(i,e,l,d,c,u){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="release-notes" tabindex="-1">Release Notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release Notes&quot;">​</a></h1><h2 id="_2026-07-11-latest" tabindex="-1">2026-07-11 (latest) <a class="header-anchor" href="#_2026-07-11-latest" aria-label="Permalink to &quot;2026-07-11 (latest)&quot;">​</a></h2><h3 id="new-features" tabindex="-1">New features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><strong>Inline markdown table editor</strong> — placing the cursor inside a markdown table now opens a focused grid editor for direct cell/header updates.</li></ul><h3 id="refinements" tabindex="-1">Refinements <a class="header-anchor" href="#refinements" aria-label="Permalink to &quot;Refinements&quot;">​</a></h3><ul><li><strong>Compact table actions</strong> — row/column controls now use labeled compact action chips for quicker recognition and less visual noise.</li><li><strong>Table edit interaction flow</strong> — deleting rows/columns keeps editing context active instead of dropping back to the main editor.</li><li><strong>Table formatting preservation</strong> — same-shape table edits now preserve the original table style (spacing and delimiter style) where possible.</li></ul><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li><strong>Escaped content safety</strong> — table parsing now preserves escaped pipes and plain backslashes in cell content (including Windows-style paths).</li><li><strong>Scroll behavior during table edits</strong> — background scrolling is disabled while table editing is active; table content scrolling remains within the editor panel.</li></ul><hr><h2 id="_2026-07-03-latest" tabindex="-1">2026-07-03 (latest) <a class="header-anchor" href="#_2026-07-03-latest" aria-label="Permalink to &quot;2026-07-03 (latest)&quot;">​</a></h2><h3 id="new-features-1" tabindex="-1">New features <a class="header-anchor" href="#new-features-1" aria-label="Permalink to &quot;New features&quot;">​</a></h3><ul><li><strong>Open Workspace in VS Code</strong> — the landing <strong>File</strong> menu now includes <strong>Open Workspace in VS Code</strong> (<code>Ctrl/Cmd + Shift + O</code>). Opens the active workspace folder directly in VS Code, or falls back to the system default app.</li><li><strong>Reveal Workspace in File Explorer</strong> — the landing <strong>File</strong> menu now includes <strong>Reveal Workspace in File Explorer</strong> (<code>Ctrl/Cmd + Shift + J</code>). Opens the workspace folder in the native system file browser.</li><li><strong>Web menu</strong> — a new top-level <strong>Web</strong> menu (<code>Ctrl/Cmd + Shift + W</code>) provides one-click access to the project website (landing screen) or the current note&#39;s website view (note screen).</li><li><strong>Custom dropdown controls</strong> — all select/dropdown controls across the app have been replaced with a fully custom listbox component. The new control supports grouped options, keyboard navigation (arrow keys, Home, End, Enter, Escape), selected-state checkmarks, and focus-aware close behaviour.</li></ul><h3 id="refinements-1" tabindex="-1">Refinements <a class="header-anchor" href="#refinements-1" aria-label="Permalink to &quot;Refinements&quot;">​</a></h3><ul><li><strong>Form focus styles</strong> — focus indicators across all inputs, selects, and textareas have been softened to a subtle border tint and <code>2px</code> halo for a more professional desktop feel.</li><li><strong>Continue Writing panel</strong> — now shows only the single most recently edited note instead of a list, making it faster to resume work.</li><li><strong>Task hover popover</strong> — the note-level task summary popover now sizes to the available viewport height before showing a scrollbar.</li><li><strong>Note detail topbar consistency</strong> — breadcrumb chips, task summary, save status, and action controls now use aligned heights and shared corner radius styling for a cleaner, unified row.</li></ul><h3 id="fixes-1" tabindex="-1">Fixes <a class="header-anchor" href="#fixes-1" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li><strong>Workspace switch website refresh</strong> — opening project website view after changing workspace now reflects the current workspace immediately instead of reusing stale scope from the previous folder.</li><li><strong>Task summary accessibility semantics</strong> — the topbar task summary trigger now uses button semantics with screen-reader state attributes for improved accessibility.</li></ul><hr><h2 id="_2026-07-03" tabindex="-1">2026-07-03 <a class="header-anchor" href="#_2026-07-03" aria-label="Permalink to &quot;2026-07-03&quot;">​</a></h2><p>This release focuses on documentation accuracy, shortcut clarity, and in-app help coverage.</p><h3 id="documentation-updates" tabindex="-1">Documentation updates <a class="header-anchor" href="#documentation-updates" aria-label="Permalink to &quot;Documentation updates&quot;">​</a></h3><ul><li>Updated user docs to match current UI labels such as <strong>Open Workspace</strong> and <strong>Help Center</strong></li><li>Added a dedicated <strong>Settings Reference</strong> page</li><li>Added an <strong>FAQ</strong> page</li><li>Added this <strong>Release Notes</strong> page and a repository <code>CHANGELOG.md</code></li></ul><h3 id="shortcut-updates" tabindex="-1">Shortcut updates <a class="header-anchor" href="#shortcut-updates" aria-label="Permalink to &quot;Shortcut updates&quot;">​</a></h3><ul><li>Resolved overlapping shortcut definitions for the command palette, AI palette, focus mode, and outline workflows</li><li>Expanded the in-app keyboard shortcuts guide to include context-specific shortcuts and usage notes</li></ul><h3 id="help-center-updates" tabindex="-1">Help Center updates <a class="header-anchor" href="#help-center-updates" aria-label="Permalink to &quot;Help Center updates&quot;">​</a></h3><ul><li>Added new Help Center entries for settings, FAQ, and release notes</li><li>Updated task and troubleshooting documentation to cover current workflows more accurately</li></ul><h2 id="notes-for-existing-users" tabindex="-1">Notes for existing users <a class="header-anchor" href="#notes-for-existing-users" aria-label="Permalink to &quot;Notes for existing users&quot;">​</a></h2><ul><li>If you learned older menu names such as <strong>Notes Folder</strong> or <strong>Documentation</strong>, use <strong>Open Workspace</strong> and <strong>Help Center</strong> instead.</li><li>If you used older overlapping shortcuts, open the keyboard guide once to confirm the current bindings.</li></ul>',27)])])}const g=t(r,[["render",n]]);export{p as __pageData,g as default};
